#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
==============================================

This script provides functionality for managing Python dependency lock files
to ensure consistent versions across development and production environments.

Usage:
    python dependency_manager.py generate-lock
    python dependency_manager.py update-lock
    python dependency_manager.py verify-lock
"""

import os
import sys
import subprocess
import json
import hashlib
from pathlib import Path
from typing import List, Dict, Any

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_txt = self.project_root / "requirements.txt"
        self.poetry_lock = self.project_root / "poetry.lock"
        self.pyproject_toml = self.project_root / "pyproject.toml"
        self.lock_file = self.project_root / "requirements.lock"
        
    def generate_requirements_txt(self) -> None:
        """Generate requirements.txt with hashes from pip-compile"""
        try:
            subprocess.run([
                "pip-compile", 
                "--generate-hashes",
                "--output-file", str(self.requirements_txt),
                "pyproject.toml"
            ], check=True, capture_output=True)
            print("✅ Generated requirements.txt with hashes")
        except subprocess.CalledProcessError as e:
            print(f"❌ Error generating requirements.txt: {e}")
            sys.exit(1)
            
    def generate_lock_file(self) -> None:
        """Generate lock file from requirements.txt"""
        if not self.requirements_txt.exists():
            self.generate_requirements_txt()
            
        # Create hash-based lock file
        lock_data = self._read_requirements_with_hashes()
        self._write_lock_file(lock_data)
        print("✅ Generated lock file")
        
    def update_dependencies(self) -> None:
        """Update dependencies to latest compatible versions"""
        try:
            # Update dependencies
            subprocess.run(["pip-compile", "--upgrade", "--generate-hashes"], 
                         check=True, capture_output=True)
            print("✅ Dependencies updated")
            
            # Regenerate lock file
            self.generate_lock_file()
            print("✅ Lock file updated")
            
        except subprocess.CalledProcessError as e:
            print(f"❌ Error updating dependencies: {e}")
            sys.exit(1)
            
    def verify_lock_file(self) -> bool:
        """Verify that lock file matches current requirements"""
        if not self.lock_file.exists():
            print("⚠️  Lock file not found")
            return False
            
        requirements_hash = self._calculate_requirements_hash()
        lock_hash = self._read_lock_hash()
        
        if requirements_hash == lock_hash:
            print("✅ Lock file is valid")
            return True
        else:
            print("⚠️  Lock file is outdated")
            return False
            
    def _read_requirements_with_hashes(self) -> List[Dict[str, str]]:
        """Read requirements.txt and extract package information"""
        packages = []
        if not self.requirements_txt.exists():
            return packages
            
        with open(self.requirements_txt, 'r') as f:
            lines = f.readlines()
            
        for line in lines:
            line = line.strip()
            if line and not line.startswith('#') and not line.startswith('-'):
                # Parse package name and hash
                if ' --hash=' in line:
                    parts = line.split(' --hash=')
                    package_name = parts[0].split('==')[0]
                    package_hash = parts[1]
                    packages.append({
                        'name': package_name,
                        'hash': package_hash
                    })
                    
        return packages
        
    def _write_lock_file(self, packages: List[Dict[str, str]]) -> None:
        """Write lock file with package information"""
        lock_data = {
            'packages': packages,
            'hash': self._calculate_requirements_hash()
        }
        
        with open(self.lock_file, 'w') as f:
            json.dump(lock_data, f, indent=2)
            
    def _calculate_requirements_hash(self) -> str:
        """Calculate hash of requirements.txt content"""
        if not self.requirements_txt.exists():
            return ""
            
        content = self.requirements_txt.read_text()
        return hashlib.sha256(content.encode()).hexdigest()
        
    def _read_lock_hash(self) -> str:
        """Read hash from lock file"""
        if not self.lock_file.exists():
            return ""
            
        with open(self.lock_file, 'r') as f:
            data = json.load(f)
            return data.get('hash', '')

def main():
    """Main entry point for dependency management"""
    manager = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [generate-lock|update-lock|verify-lock]")
        sys.exit(1)
        
    command = sys.argv[1]
    
    if command == "generate-lock":
        manager.generate_lock_file()
    elif command == "update-lock":
        manager.update_dependencies()
    elif command == "verify-lock":
        manager.verify_lock_file()
    else:
        print("Unknown command. Use: generate-lock, update-lock, or verify-lock")
        sys.exit(1)

if __name__ == "__main__":
    main()